                          fontWeight: FontWeight.w600,
                          letterSpacing: 0.3,
                          color: colorScheme.onSurface,
                        ),
                      ),
                      if (auth?.user?.email != null) ...[
                        const SizedBox(height: 4),
                        Text(
                          auth!.user!.email!,
