                                      context,
                                      colorScheme,
                                      isPhone,
                                    )
                                  : _buildFullContent(
                                      context,
                                      colorScheme,
                                      isDark,
                                      isPhone,
                                    ),
                            ),
                          ),
                        ),
                        // Minimize / restore button вЂ” always visible, top-right
                        if (widget.onToggleMinimize != null)
                          Positioned(
                            top: 4,
                            right: 4,
                            child: Material(
                              color: Colors.transparent,
                              child: InkWell(
                                onTap: widget.onToggleMinimize,
                                borderRadius: BorderRadius.circular(12),
                                child: Padding(
                                  padding: const EdgeInsets.all(4),
                                  child: Icon(
                                    minimized
                                        ? Icons.open_in_full
                                        : Icons.close_fullscreen,
                                    size: 14,
                                    color: colorScheme.onSurface.withValues(
                                      alpha: 0.4,
                                    ),
                                  ),
                                ),
                              ),
                            ),
                          ),
                      ],
                    ),
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

