  /// Drags a scrollable ListView until a widget with the given key is found.
  /// Useful for finding widgets that are offscreen.
  static Future<void> dragUntil(
    WidgetTester tester, {
    String listViewName = 'listView',
    required String key,
  }) async {
    int times = 0;
    bool found = false;
    // dismiss keyboard if open
    FocusManager.instance.primaryFocus?.unfocus();
    await tester.pumpAndSettle();
    do {
      found = tester.any(find.byKey(Key(key)));
      if (found) break;
      final listViewFinder = find.byKey(Key(listViewName));
      if (tester.any(listViewFinder)) {
        await tester.drag(listViewFinder.last, const Offset(0, -200));
      } else {
        // ListView not found, break to avoid repeated failures
        break;
      }
      await tester.pumpAndSettle(const Duration(milliseconds: 100));
    } while (times++ < 10 && !found);
    expect(
      found,
      true,
      reason: 'Widget with key "$key" not found after scrolling.',
    );
    // Extra scrolling to ensure element is fully visible and centered
    final listViewFinder = find.byKey(Key(listViewName));
    for (int i = 0; i < 3; i++) {
      if (tester.any(listViewFinder)) {
        await tester.drag(listViewFinder.last, const Offset(0, -150));
        await tester.pumpAndSettle(const Duration(milliseconds: 50));
      }
    }
    // Ensure the widget is visible
    await tester.ensureVisible(find.byKey(Key(key)));
    await tester.pumpAndSettle();
  }

