  /// Enter value into an Autocomplete field and select a matching option.
  /// [key] is the Key of the Autocomplete widget.
  /// [value] is the search text; the first option containing this text is tapped.
  static Future<void> enterAutocompleteValue(
    WidgetTester tester,
    String key,
    String value,
  ) async {
    final autocomplete = find.byKey(Key(key));
    if (!tester.any(autocomplete)) {
      debugPrint('Warning: Autocomplete with key $key not found');
      return;
    }

    // Ensure the autocomplete widget is visible before interacting
    await tester.ensureVisible(autocomplete.first);
    await tester.pumpAndSettle();

    // Dismiss any existing keyboard / focus to avoid interference
    FocusManager.instance.primaryFocus?.unfocus();
    await tester.pumpAndSettle();

    // Find the text field within the autocomplete
    final textField = find.descendant(
      of: autocomplete,
      matching: find.byType(TextFormField),
    );

    if (!tester.any(textField)) {
      debugPrint('Warning: TextFormField not found in Autocomplete $key');
      return;
    }

    // Tap to focus the field
    await tester.tap(textField.first);
    await tester.pumpAndSettle();

    // Clear the field and enter new text
    await tester.enterText(textField.first, '');
    await tester.pumpAndSettle();
    await tester.enterText(textField.first, value);

    // Wait generously for optionsBuilder to complete
    await tester.pump(const Duration(seconds: waitTime));
    await tester.pumpAndSettle();

    // Approach 1: Find dropdown option ListTiles in the Overlay.
    // Autocomplete renders its options in an Overlay, so look for ListTiles
    // that contain the search text but live outside the form (no TextFormField
    // ancestor within the same ListTile).
    final allContaining = find.textContaining(value);
    if (tester.any(allContaining)) {
      for (int i = 0; i < allContaining.evaluate().length; i++) {
        final element = allContaining.evaluate().elementAt(i);
        // Walk up to the nearest ListTile
        Element? listTileElement;
        element.visitAncestorElements((ancestor) {
          if (ancestor.widget is ListTile) {
            listTileElement = ancestor;
            return false;
          }
          return true;
        });
        if (listTileElement != null) {
          // Check if this ListTile also contains a TextFormField
          // (which would mean it's the form row, not a dropdown option)
          final listTileFinder = find.byElementPredicate(
            (el) => el == listTileElement,
          );
          final formFieldInListTile = find.descendant(
            of: listTileFinder,
            matching: find.byType(TextFormField),
          );
          if (!tester.any(formFieldInListTile)) {
            // This ListTile is a dropdown option, not a form row
            await tester.tap(listTileFinder.first);
            await tester.pumpAndSettle();
            return;
          }
        }
      }
    }

    // Approach 2: Try tapping a matching item in any visible ListView
    // that isn't the main form list.
    final listTiles = find.byType(ListTile);
    for (int i = 0; i < listTiles.evaluate().length; i++) {
      final tile = listTiles.evaluate().elementAt(i);
      final tileFinder = find.byElementPredicate((el) => el == tile);
      final textInTile = find.descendant(
        of: tileFinder,
        matching: find.textContaining(value),
      );
      final formFieldInTile = find.descendant(
        of: tileFinder,
        matching: find.byType(TextFormField),
      );
      if (tester.any(textInTile) && !tester.any(formFieldInTile)) {
        await tester.tap(tileFinder.first);
        await tester.pumpAndSettle();
        return;
      }
    }

    // Approach 3: Keyboard navigation fallback
    await tester.sendKeyEvent(LogicalKeyboardKey.arrowDown);
    await tester.pumpAndSettle();
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pumpAndSettle();
  }

  static Future<void> enterText(
    WidgetTester tester,
    String key,
    String value,
  ) async {
    await tester.pump();
    // Try to find the widget, if not found wait a bit and try again
    final finder = find.byKey(Key(key));
    if (!tester.any(finder)) {
      // Widget not found, wait and try again
      await tester.pumpAndSettle();
      if (!tester.any(finder)) {
        // Still not found, this is an error
        throw StateError('Widget with key "$key" not found');
      }
    }
    // Ensure the widget is visible before interacting
    await tester.ensureVisible(finder);
    await tester.pumpAndSettle();
    // Tap to focus, clear existing content, then enter new text
    await tester.tap(finder.last);
    await tester.pump();
    await tester.enterText(finder.last, '');
    await tester.pump();
    await tester.enterText(finder.last, value);
    await tester.pumpAndSettle();
  }

  static Future<void> enterDate(
    WidgetTester tester,
    String key,
    DateTime date, {
    bool usDate = false,
  }) async {
    await tapByKey(tester, key);
    // Try to switch to input mode if the button exists
    final switchButton = find.byTooltip('Switch to input');
    if (tester.any(switchButton)) {
      await tapByTooltip(tester, 'Switch to input');
    }
    await tester.enterText(
      find.byType(TextField).last,
      DateFormat(usDate ? 'MM/dd/yyyy' : 'yyyy-MM-dd').format(date),
    );
    await tester.pump();
    await CommonTest.tapByText(tester, 'OK');
  }

  static Future<void> enterDropDownSearch(
    WidgetTester tester,
    String key,
    String value, {
    int seconds = 1,
    check = false,
  }) async {
    final finder = find.byKey(Key(key));
    if (finder.evaluate().isNotEmpty) {
      await tester.ensureVisible(finder.first);
      await tester.pumpAndSettle();
    }
    await enterAutocompleteValue(tester, key, value);
  }

  static Future<void> enterDropDown(
    WidgetTester tester,
    String key,
    String value, {
    int seconds = 1,
  }) async {
    // Ensure the dropdown button is visible before interacting
    await dragUntil(tester, key: key);

    // Tap to open the dropdown
    await tester.tap(find.byKey(Key(key)));
    await tester.pumpAndSettle(Duration(seconds: seconds));

    // Find the item in the dropdown.
    // When value is empty, scope the finder to DropdownMenuItem descendants to
    // avoid accidentally matching background EditableText widgets (e.g. form
    // fields behind the overlay) that also have empty content.  Using the
    // broad find.text('') on those widgets produces a tap-offset warning
    // because the resolved position does not hit-test the intended widget.
    Finder itemFinder;
    if (value.isEmpty) {
      itemFinder = find.descendant(
        of: find.byType(DropdownMenuItem),
        matching: find.text(value),
      );
      // Fallback to broad search if no DropdownMenuItem is found (e.g. custom
      // dropdown implementations).
      if (itemFinder.evaluate().isEmpty) {
        itemFinder = find.text(value);
      }
    } else {
      itemFinder = find.textContaining(value);
    }

    // If item not found, scroll within the dropdown to find it
    if (itemFinder.evaluate().isEmpty) {
      // Look for the dropdown's ListView and scroll it
      final dropdownFinder = find.byType(ListView);
      if (tester.any(dropdownFinder)) {
        // Scroll down until item is found
        for (int i = 0; i < 10; i++) {
          await tester.drag(dropdownFinder.last, const Offset(0, -100));
          await tester.pumpAndSettle();
          if (itemFinder.evaluate().isNotEmpty) {
            break;
          }
        }
      }
    }

    // Verify the item was found
    expect(
      itemFinder.evaluate().isNotEmpty,
      true,
      reason: 'Could not find dropdown item with value: $value',
    );

    // Ensure the item is visible and tap it
    await tester.ensureVisible(itemFinder.last);
    await tester.pumpAndSettle();
    await tester.tap(itemFinder.last, warnIfMissed: false);
    await tester.pumpAndSettle();
  }

  static String getDropdown(
    String key, {
    String classificationId = 'AppAdmin',
  }) {
    DropdownButtonFormField tff =
        find.byKey(Key(key)).last.evaluate().single.widget
            as DropdownButtonFormField;
    // Support both initialValue and value properties
    final val = tff.initialValue ?? (tff as dynamic).value;
    if (val == null) return '';
    if (val is Currency) return val.description ?? '';
    if (val is UserGroup) return val.toString();
    if (val is RequestType) return val.toString();
    if (val is Role) return val.value;
    if (val is FinDocStatusVal) {
      return classificationId == 'AppHotel' ? val.hotel : val.name;
    }
    return val.toString();
  }

  static String getDropdownSearch(String key) {
    final finder = find.byKey(Key(key));
    // If not found, return empty or throw? Original threw exception implicitly via .single
    if (finder.evaluate().isEmpty) {
      throw StateError('Widget with key "$key" not found');
    }

    final widget = finder.evaluate().single.widget;
    if (widget is Autocomplete || widget is AutocompleteLabel) {
      final textFinder = find.descendant(
        of: finder,
        matching: find.byType(TextFormField),
      );
      if (textFinder.evaluate().isNotEmpty) {
        TextFormField tff =
            textFinder.evaluate().single.widget as TextFormField;
        return tff.controller?.text ?? '';
      }
    }
    return widget.toString();
  }

  /// get the state of a switch field identified by a key
  static bool? getSwitchField(String key) {
    final finder = find.byKey(Key(key), skipOffstage: false);
    expect(
      finder,
      findsWidgets,
      reason: 'No Switch widget found with key "$key"',
    );
    Switch tff = finder.last.evaluate().single.widget as Switch;
    return tff.value;
  }

  /// get the content of a text field identified by a key
  static String getTextField(String key) {
    final finder = find.byKey(Key(key), skipOffstage: false);
    expect(
      finder,
      findsWidgets,
      reason: 'No Text widget found with key "$key")}',
    );
    Text tf = finder.last.evaluate().single.widget as Text;
    return tf.data!;
  }

  /// get the content of a TextFormField providing the key
  static String getTextFormField(String key) {
    TextFormField tff =
        find.byKey(Key(key)).evaluate().single.widget as TextFormField;
    return tff.controller!.text;
  }

  /// get the content of a TextFormField providing the key
  static DateTime getDateTimeFormField(String key) {
    FormField<DateTime> tff =
        find.byKey(Key(key)).evaluate().single.widget as FormField<DateTime>;
    return tff.initialValue as DateTime;
  }

  static String getFormBuilderTextFieldByName(
    WidgetTester tester,
    String name,
  ) {
    // Find the FormBuilder field by its unique name.
    final formFieldFinder = find.byWidgetPredicate(
      (widget) => widget is FormBuilderTextField && (widget).name == name,
    );
    expect(
      formFieldFinder,
      findsOneWidget,
      reason: 'Could not find a FormBuilderTextField with name "$name"',
    );

    // The FormBuilderTextField wraps a standard TextField. We need to find it.
    final textFieldFinder = find.descendant(
      of: formFieldFinder,
      matching: find.byType(TextField),
    );
    expect(
      textFieldFinder,
      findsOneWidget,
      reason: 'Could not find the underlying TextField for "$name"',
    );

    // Get the widget instance and read the text from its controller.
    final textField = tester.widget<TextField>(textFieldFinder);
    return textField.controller!.text;
  }

  static bool getCheckbox(String key) {
    Checkbox tff = find.byKey(Key(key)).evaluate().single.widget as Checkbox;
    return tff.value ?? false;
  }

  static bool getRadio(String key) {
    Radio tff = find.byKey(Key(key)).evaluate().single.widget as Radio;
    return tff.value;
  }

  static bool getCheckboxListTile(String text) {
    CheckboxListTile tff =
        find.text(text).evaluate().single.widget as CheckboxListTile;
    return tff.value ?? false;
  }

  static bool isPhone() {
    try {
      expect(find.byTooltip('Open navigation menu'), findsOneWidget);
      return true;
    } catch (_) {
      return false;
    }
  }

  static bool hasKey(String key) {
    if (find
        .byKey(Key(key))
        .toString()
        .startsWith('Found 0 widgets with key')) {
      return false;
    }
    return true;
  }

  static Future<void> selectMainMenu(
    WidgetTester tester,
    String menuOption,
  ) async {
    if (hasKey('cancel')) {
      // company or user detail menu open?
      await tester.tap(find.byKey(const Key('cancel')).last);
      await tester.pump();
    }
    if (!hasKey('HomeFormAuth')) {
      if (isPhone()) {
        await tester.tap(find.byTooltip('Open navigation menu'));
        await tester.pump();
        await tester.pumpAndSettle(const Duration(seconds: waitTime));
      }
      await tapByKey(tester, menuOption);
    }
  }

  static Future<void> tapByKey(
    WidgetTester tester,
    String key, {
    int seconds = 1,
    bool settle = true, // If false, use pump instead of pumpAndSettle
  }) async {
    await tester.pump();
    expect(
      tester.any(find.byKey(Key(key))),
      true,
      reason: "could not find key: $key to tap on",
    );
    await tester.ensureVisible(find.byKey(Key(key)).last);
    await tester.tap(find.byKey(Key(key)).last);
    await tester.pump();
    if (settle) {
      await tester.pumpAndSettle(Duration(seconds: seconds));
    } else {
      await tester.pump(Duration(seconds: seconds));
    }
  }

  static Future<void> tapByWidget(
    WidgetTester tester,
    Widget widget, {
    int seconds = 1,
  }) async {
    await tester.tap(find.byWidget(widget).first);
    await tester.pumpAndSettle(Duration(seconds: seconds));
  }

  static Future<void> tapByType(
    WidgetTester tester,
    Type type, {
    int seconds = 1,
  }) async {
    await tester.tap(find.byType(type).first);
    await tester.pumpAndSettle(Duration(seconds: seconds));
  }

  static Future<void> tapByText(
    WidgetTester tester,
    String text, {
    int seconds = 1,
  }) async {
    final baseFinder = find.textContaining(RegExp(text, caseSensitive: false));
    expect(
      tester.any(baseFinder),
      true,
      reason: "could not find text: '$text' to tap on",
    );
    final finder = baseFinder.last;
    await tester.ensureVisible(finder);
    await tester.pumpAndSettle();
    await tester.tap(finder);
    await tester.pumpAndSettle(Duration(seconds: seconds));
  }

  static Future<void> tapByTooltip(
    WidgetTester tester,
    String text, {
    int seconds = 1,
  }) async {
    await tester.tap(find.byTooltip(text));
    await tester.pumpAndSettle(Duration(seconds: seconds));
  }

  static Future<void> selectDropDown(
    WidgetTester tester,
    String key,
    String value, {
    seconds = 1,
  }) async {
    await tapByKey(tester, key, seconds: seconds);
    await tapByText(tester, value);
  }

  static String getRandom() {
    Text tff =
        find.byKey(const Key('appBarCompanyName')).evaluate().single.widget
            as Text;
    return tff.data!.replaceAll(RegExp(r'[^0-9]'), '');
  }

  static int getWidgetCountByKey(WidgetTester tester, String key) {
    var finder = find.byKey(Key(key));
    return tester.widgetList(finder).length;
  }

  static void mockPackageInfo() {
    const channel = MethodChannel('plugins.flutter.io/package_info');

    handler(MethodCall methodCall) async {
      if (methodCall.method == 'getAll') {
        return <String, dynamic>{
          'appName': 'myapp',
          'packageName': 'com.mycompany.myapp',
          'version': '0.0.1',
          'buildNumber': '1',
        };
      }
      return null;
    }

    TestWidgetsFlutterBinding.ensureInitialized();

    TestDefaultBinaryMessengerBinding.instance.defaultBinaryMessenger
        .setMockMethodCallHandler(channel, handler);
  }

  static void mockImagePicker() {
    const MethodChannel channel = MethodChannel(
      'plugins.flutter.io/image_picker',
    );

    handler(MethodCall methodCall) async {
      ByteData data = await rootBundle.load('assets/images/crm.png');
      Uint8List bytes = data.buffer.asUint8List();
      Directory tempDir = await getTemporaryDirectory();
      File file = await File('${tempDir.path}/tmp.tmp').writeAsBytes(bytes);
      debugPrint('=========${file.path}');
      return [
        // file.path;
        {
          'name': "Icon.png",
          'path': file.path,
          'bytes': bytes,
          'size': bytes.lengthInBytes,
        },
      ];
    }

    TestWidgetsFlutterBinding.ensureInitialized();

    TestDefaultBinaryMessengerBinding.instance.defaultBinaryMessenger
        .setMockMethodCallHandler(channel, handler);
  }

  static void mockUrlLauncher() {
    const MethodChannel channel = MethodChannel(
      'plugins.flutter.io/url_launcher',
    );

    handler(MethodCall methodCall) async {
      debugPrint("=========$methodCall");
    }

    TestWidgetsFlutterBinding.ensureInitialized();

    TestDefaultBinaryMessengerBinding.instance.defaultBinaryMessenger
        .setMockMethodCallHandler(channel, handler);
  }

  static Future<String?> getRelatedFindoc(
    WidgetTester tester,
    FinDocType type,
  ) async {
    if (tester.any(find.byKey(Key("rel$type"))) == false) {
      debugPrint('DEBUG getRelatedFindoc: rel$type NOT found');
      return null;
    }
    debugPrint('DEBUG getRelatedFindoc: rel$type FOUND, tapping...');
    await tapByKey(tester, "rel$type");
    String id = getTextField('topHeader').split('#')[1].trim();
    debugPrint('DEBUG getRelatedFindoc: got id=$id, tapping cancel...');
    // Tapping relXxx calls context.push('/findoc') which pushes a GoRouter
    // route showing a full-page dialog.  Tap the cancel button which uses
    // context.pop() to pop the GoRouter route and return to the previous page.
    await tapByKey(tester, 'cancel');
    await tester.pumpAndSettle(const Duration(seconds: 2));
    debugPrint('DEBUG getRelatedFindoc: returned from rel$type with id=$id');
    return id;
  }

  static List<String> checkFormBuilderTextfields(
    FormBuilderState formState,
    Map<String, dynamic> expectedFields,
  ) {
    List<String> errors = [];
    for (var entry in expectedFields.entries) {
      if (formState.value[entry.key] != entry.value) {
        errors.add(
          'Field ${entry.key} has value ${formState.value[entry.key]} but expected ${entry.value}',
        );
      }
    }
    return (errors);
  }
}

