  static Future<void> selectOption(
    WidgetTester tester,
    String option,
    String formName, [
    String? tapNumber,
  ]) async {
    // First, transform the option to get the target key
    String targetKey = option;
    if (!targetKey.startsWith('tap')) {
      if (targetKey.startsWith('db')) {
        // convert old mainscreen tapping to drawer on mobile
        targetKey = "/${targetKey.substring(2).toLowerCase()}";
      } else if (!targetKey.startsWith('/')) {
        targetKey = "/$targetKey";
      }
      targetKey = "tap$targetKey";
    }

    // Check if the key is already visible (for dashboard cards or navigation rail)
    bool keyAlreadyVisible = tester.any(find.byKey(Key(targetKey)));

    // Handle visibility: either open drawer (phone) or scroll dashboard (tablet/desktop)
    if (!keyAlreadyVisible) {
      if (isPhone()) {
        expect(
          find.byTooltip('Open navigation menu'),
          findsOneWidget,
          reason: "could not find tooltip: 'Open navigation menu' to tap on",
        );
        await tester.tap(find.byTooltip('Open navigation menu'));
        await tester.pump(const Duration(seconds: waitTime));
        await tester.pumpAndSettle();
      } else {
        // On tablet/desktop, try scrolling the dashboard grid if it exists
        if (tester.any(find.byKey(const Key('dashboard_scroll')))) {
          try {
            await dragUntil(
              tester,
              listViewName: 'dashboard_scroll',
              key: targetKey,
            );
          } catch (_) {
            // ignore if dragUntil fails, tapByKey will throw the final error
          }
        }
      }
    }

    await tapByKey(tester, targetKey, seconds: waitTime, settle: false);
    // Wait for navigation to complete
    await tester.pumpAndSettle(const Duration(seconds: waitTime));

    if (tapNumber != null) {
      // Both phone (BottomNavigationBar) and desktop (TabBar) use text labels
      // Newlines in titles are replaced with spaces in BottomNavigationBar labels
      await tapByText(tester, tapNumber.replaceAll('\n', ' '));
      await tester.pumpAndSettle(const Duration(seconds: waitTime));
    }
    bool formFound = await waitForKey(tester, formName);
    if (!formFound) {
      await tester.pumpAndSettle(const Duration(seconds: waitTime));
      if (tester.any(find.byKey(Key(targetKey)))) {
        await tapByKey(tester, targetKey, seconds: waitTime, settle: false);
        await tester.pumpAndSettle(const Duration(seconds: waitTime));
        if (tapNumber != null) {
          await tapByText(tester, tapNumber.replaceAll('\n', ' '));
          await tester.pumpAndSettle(const Duration(seconds: waitTime));
        }
      }
      formFound = await waitForKey(tester, formName);
    }
    expect(
      formFound,
      true,
      reason: 'key $formName not found after selecting option $option',
    );
    await checkWidgetKey(tester, formName);
  }

