  static Future<void> selectMainMenu(
    WidgetTester tester,
    String menuOption,
  ) async {
    if (hasKey('cancel')) {
      // company or user detail menu open?
      await tester.tap(find.byKey(const Key('cancel')).last);
      await tester.pump();
    }
    // If not already on home screen, use home button or menu option
    if (!hasKey('HomeFormAuth') && !hasKey('LinerExampleDashboard')) {
      if (hasKey('homeButton')) {
        await tapByKey(tester, 'homeButton');
      } else {
        if (isPhone()) {
          await tester.tap(find.byTooltip('Open navigation menu'));
          await tester.pump();
          await tester.pumpAndSettle(const Duration(seconds: waitTime));
